      {
       "chuong": "@c0280",
       "importance": "normal",
       "mucCt": "vua",
       "tieuDe": "Ân nghĩa Tần gia",
       "text": "Lý Hóa Nguyên được Tần Ngôn nhắc tới như vị tiên sư từng có đại ân với Tần gia, đồng thời là người phái Hàn Lập đến. Trong mật thất, Hàn Lập xác nhận Lý tiên sư chính là gia sư của mình, khiến việc bảo hộ Tần gia có căn cứ rõ ràng.",
       "anchor": "Lý tiên sư trong miệng người chính là gia sư"
      },
      {
       "chuong": "@c0285",
       "importance": "bridge",
       "mucCt": "gon",
       "text": "Lý Hóa Nguyên được Hàn Lập nhớ tới như người khiến hắn phải bảo vệ tính mạng Tần Ngôn để có thể trở về ăn nói.",
       "anchor": "Nếu mà không được, thì ít nhất phải bảo vệ được tính mạng của Tần Ngôn, nếu không thì lúc trở về không biết ăn nói sao với Lý Hóa Nguyên."
      },
      {
       "chuong": "@c0288",
       "importance": "bridge",
       "mucCt": "gon",
       "text": "Được Tần Ngôn nhớ lại là từng đến Tần gia xem hậu bối có tiên duyên hay không nhưng không thu được đệ tử.",
       "anchor": "Theo cách nói của Lý Hóa Nguyên tiên sinh, tiên duyên của hắn và Tần gia chỉ trong một thế hệ."
      },
      {
       "chuong": "@c0293",
       "importance": "bridge",
       "mucCt": "gon",
       "tieuDe": "Được Hàn Lập nhớ lại",
       "text": "Lý Hóa Nguyên được Hàn Lập nhớ tới khi hắn so sánh ánh mắt hâm mộ của tiểu cô nương với lần đầu mình thấy Lý Hóa Nguyên sử dụng Cự Giao.",
       "anchor": "Nhớ lại lần đầu tiên hắn nhìn thấy Lý Hóa Nguyên sử dụng Cự Giao cũng toát lên ánh mắt cực kỳ hâm mộ như vậy."
      },
      {
       "chuong": "@c0299",
       "importance": "bridge",
       "mucCt": "gon",
       "tieuDe": "Ràng buộc nhiệm vụ",
       "text": "Nhiệm vụ bảo hộ Tần gia do Lý Hóa Nguyên giao khiến Hàn Lập khó rời Việt Kinh dù đã nhận ra nguy hiểm.",
       "anchor": "hắn căn bản không có biện pháp giao phó với Lý Hóa Nguyên"
      },
      {
       "chuong": "@c0302",
       "importance": "bridge",
       "mucCt": "gon",
       "text": "Lý Hóa Nguyên được Hàn Lập gửi thư cầu viện qua người liên lạc của Hoàng Phong cốc ở Việt Kinh vì vụ Hắc sát giáo phát sinh từ nhiệm vụ do ông giao.",
       "anchor": "hắn thông qua người liên lạc của Hoàng Phong cốc ở Việt Kinh gửi cho Lý Hóa Nguyên một phong thư cầu viện"
      },
      {
       "chuong": "@c0312",
       "importance": "bridge",
       "mucCt": "gon",
       "text": "Hàn Lập tính toán rằng Lý Hóa Nguyên dù phái người đến cũng nhanh nhất phải mất trên dưới mười ngày.",
       "anchor": "Lý Hóa Nguyên cho dù phái người đến, nhanh nhất cũng phải trên dưới mười ngày nữa"
      },
      {
       "chuong": "@c0313",
       "importance": "bridge",
       "mucCt": "gon",
       "text": "Lý Hóa Nguyên được nhắc là sư phụ của nhóm Hàn Lập và từng dặn Lưu Tĩnh về lực lượng hỗ trợ của Huy Minh sư bá ở Nam Ô thành.",
       "anchor": "Khi ta đi sư phụ đã từng dặn dò qua, ở Nam Ôthành gần Việt Kinh có vài ký danh đệ tử của Huy Minh sư bá đang xử lý một ít sự vụ của sư môn."
      },
      {
       "chuong": "@c0314",
       "importance": "bridge",
       "tieuDe": "Nhận thư báo việc",
       "mucCt": "gon",
       "text": "Lý Hóa Nguyên được Vũ Huyễn viết thư báo lại sự việc sau khi Vũ Huyễn rời Tần phủ.",
       "anchor": "nghe nói đã viết một bức thư cho Lý Hóa Nguyên"
      },
      {
       "chuong": "@c0320",
       "importance": "bridge",
       "mucCt": "gon",
       "text": "Lý Hóa Nguyên được đồng môn suy đoán là nguồn khiến Hàn Lập có Khôi Lỗi thuật, vì tu vi của ông đủ để đoạt pháp quyết từ tu sĩ Thiên Trúc giáo.",
       "anchor": "Người hơi hiểu về nguồn gốc của Khôi Lỗi thuật đều nghĩ rằng Hàn Lập có được công pháp từ chỗ Lý Hóa Nguyên."
      },
      {
       "chuong": "@c0322",
       "importance": "bridge",
       "tieuDe": "Được nhắc qua Lưu Tĩnh",
       "mucCt": "gon",
       "text": "Lý Hóa Nguyên được nhắc là người mà Lưu Tĩnh bái nhập môn hạ sau khi thoát khỏi tay tà tu lúc nhỏ.",
       "anchor": "cuối cùng được người nhà cứu ra, rồi bái nhập làm môn hạ của Lý Hóa Nguyên"
      },
      {
       "mucCt": "vua",
       "text": "Lý Hóa Nguyên xuất hiện dưới dạng hư ảnh trong ngọc giản và truyền lệnh không cần tiếp tục bảo hộ Tần gia. Ông cho phép Hàn Lập cùng các đệ tử khác yên tâm phản hồi biên giới.",
       "anchor": "tại trong đó xuất hiện hư ảnh của Lý Hóa Nguyên, lão nói cực kỳ đơn giản",
       "bridge": true,
       "khoang": "@c0331"
      },
      {
       "chuong": "@c0346",
       "importance": "bridge",
       "mucCt": "gon",
       "tieuDe": "Làm mốc so sánh",
       "text": "Lý Hóa Nguyên được Hàn Lập dùng làm mốc so sánh để nhận ra lão giả áo gấm đem lại cảm giác vượt xa các tu sĩ Kết Đan kỳ.",
       "anchor": "Ngay cả nhóm tu sĩ Kết Đan kỳ như Lý Hóa Nguyên cũng không cho hắn cảm giác đó."
      },
      {
       "mucCt": "vua",
       "text": "Chương thuật lại hậu sự rằng hơn mười năm sau, trong một lần sinh tử chiến với Pháp Sĩ, Lý Hóa Nguyên chết trận tại đương trường. Cái chết này khép lại tuyến sư phụ của Hàn Lập trong giai đoạn chiến sự Thiên Nam về sau.",
       "anchor": "Sư phụ của Hàn Lập, Lý Hóa Nguyên, trong một lần đánh nhau sinh tử mười mấy năm sau, cũng đã chết trận tại đương trường",
       "bridge": true,
       "khoang": "@c0363"
      }
